import java.sql.*;

public class JdbcDemo {

    static final String URL  = "jdbc:mysql://localhost:3306/devlearn?useSSL=false";
    static final String USER = "root";
    static final String PASS = "secret";

    // ── INSERT with PreparedStatement ──────────────────────────────
    static long insertUser(Connection conn, String name, String email) throws SQLException {
        String sql = "INSERT INTO users (name, email, created_at) VALUES (?, ?, NOW())";
        // Statement.RETURN_GENERATED_KEYS → get auto-increment id
        try (PreparedStatement ps = conn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS)) {
            ps.setString(1, name);
            ps.setString(2, email);
            ps.executeUpdate();
            try (ResultSet keys = ps.getGeneratedKeys()) {
                if (keys.next()) return keys.getLong(1);
            }
        }
        throw new SQLException("Insert failed — no generated key");
    }

    // ── SELECT with ResultSet ────────────────────────────────────
    static void listUsers(Connection conn) throws SQLException {
        String sql = "SELECT id, name, email FROM users WHERE active = ?";
        try (PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setBoolean(1, true);
            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) {
                    System.out.printf("[%d] %s <%s>%n",
                        rs.getLong("id"), rs.getString("name"), rs.getString("email"));
                }
            }
        }
    }

    // ── Transaction: transfer XP atomically ─────────────────────
    static void transferXP(Connection conn, long fromId, long toId, int amount) throws SQLException {
        conn.setAutoCommit(false);
        try {
            try (PreparedStatement debit = conn.prepareStatement(
                    "UPDATE users SET xp = xp - ? WHERE id = ? AND xp >= ?")) {
                debit.setInt(1, amount); debit.setLong(2, fromId); debit.setInt(3, amount);
                int rows = debit.executeUpdate();
                if (rows == 0) throw new SQLException("Insufficient XP");
            }
            try (PreparedStatement credit = conn.prepareStatement(
                    "UPDATE users SET xp = xp + ? WHERE id = ?")) {
                credit.setInt(1, amount); credit.setLong(2, toId);
                credit.executeUpdate();
            }
            conn.commit();
            System.out.println("Transferred " + amount + " XP");
        } catch (SQLException e) {
            conn.rollback(); // undo debit if credit fails
            throw e;
        } finally {
            conn.setAutoCommit(true);
        }
    }

    public static void main(String[] args) throws Exception {
        // try-with-resources: auto-closes connection
        try (Connection conn = DriverManager.getConnection(URL, USER, PASS)) {
            System.out.println("Connected: " + conn.getMetaData().getDatabaseProductName());
            // In real code, use DataSource from HikariCP pool instead of DriverManager
        }
    }
}

// ── application.properties (Spring Boot) ────────────────────────
// spring.datasource.url=jdbc:mysql://localhost:3306/devlearn
// spring.datasource.username=root
// spring.datasource.password=secret
// spring.datasource.driver-class-name=com.mysql.cj.jdbc.Driver
//
// HikariCP tuning:
// spring.datasource.hikari.maximum-pool-size=10
// spring.datasource.hikari.minimum-idle=5
// spring.datasource.hikari.connection-timeout=30000   # ms
// spring.datasource.hikari.idle-timeout=600000        # 10 min
// spring.datasource.hikari.max-lifetime=1800000       # 30 min (< MySQL wait_timeout)
// spring.datasource.hikari.pool-name=DevLearnPool

import com.zaxxer.hikari.*;
import javax.sql.DataSource;
import java.sql.*;

public class HikariCPDemo {

    static DataSource buildPool() {
        HikariConfig cfg = new HikariConfig();
        cfg.setJdbcUrl("jdbc:mysql://localhost:3306/devlearn?useSSL=false&serverTimezone=UTC");
        cfg.setUsername("root");
        cfg.setPassword("secret");

        // Pool sizing: for OLTP, start at connections = (CPU cores * 2) + 1
        cfg.setMaximumPoolSize(10);
        cfg.setMinimumIdle(3);
        cfg.setConnectionTimeout(30_000);  // 30s: throw if no connection available
        cfg.setIdleTimeout(600_000);       // 10min: close idle connections
        cfg.setMaxLifetime(1_800_000);     // 30min: recycle before MySQL kills them

        // Connection validation (lightweight ping)
        cfg.setConnectionTestQuery("SELECT 1");
        cfg.setPoolName("DevLearnPool");

        return new HikariDataSource(cfg);
    }

    // ── Batch insert using pool ───────────────────────────────────
    static void batchInsert(DataSource ds, String[] names) throws SQLException {
        String sql = "INSERT INTO tags (name) VALUES (?)";
        try (Connection conn = ds.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            for (String name : names) {
                ps.setString(1, name);
                ps.addBatch();       // queue the statement
            }
            int[] results = ps.executeBatch(); // single round-trip
            System.out.println("Batch inserted: " + results.length + " rows");
        }
    }

    // ── Pool monitoring ───────────────────────────────────────────
    static void printPoolStats(DataSource ds) {
        HikariDataSource hds = (HikariDataSource) ds;
        HikariPoolMXBean pool = hds.getHikariPoolMXBean();
        System.out.printf("Pool: total=%d, active=%d, idle=%d, waiting=%d%n",
            pool.getTotalConnections(), pool.getActiveConnections(),
            pool.getIdleConnections(), pool.getThreadsAwaitingConnection());
    }

    public static void main(String[] args) throws Exception {
        DataSource ds = buildPool();
        // Each ds.getConnection() borrows from pool;
        // try-with-resources returns it on close()
        try (Connection conn = ds.getConnection()) {
            System.out.println("Borrowed connection: " + conn);
        } // auto-returned to pool here
        printPoolStats(ds);
    }
}

