    static List<String> findUsersByName(Connection conn, String name) throws SQLException {
        List<String> emails = new ArrayList<>();
        Statement stmt = conn.createStatement();
        ResultSet rs = stmt.executeQuery("SELECT email FROM users WHERE name='" + name + "'");
        while (rs.next()) emails.add(rs.getString("email"));
        return emails;
    }

    // Also explain what happens with: name = "' OR '1'='1"
    public static void main(String[] args) {
        System.out.println("Injection input: ' OR '1'='1");
        System.out.println("Resulting SQL: SELECT email FROM users WHERE name='' OR '1'='1'");
        System.out.println("Effect: returns ALL emails");
    }
