problems.solutionCode:
import java.sql.*;
import java.util.*;

public class Q1 {
    // Fixed: PreparedStatement
    static List<String> findUsersByName(Connection conn, String name) throws SQLException {
        List<String> emails = new ArrayList<>();
        String sql = "SELECT email FROM users WHERE name = ?";
        try (PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, name); // driver escapes — ' OR '1'='1 treated as literal
            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) emails.add(rs.getString("email"));
            }
        }
        return emails;
    }

    public static void main(String[] args) {
        System.out.println("Injection input: ' OR '1'='1");
        System.out.println("PreparedStatement: treated as literal string, no rows match");
        System.out.println("Safe: no injection possible");
    }
}

