import java.sql.*;
import java.util.*;

public class Q2 {
    static int batchInsert(Connection conn, List<String> tags) throws SQLException {
        conn.setAutoCommit(false);
        String sql = "INSERT INTO tags (name) VALUES (?)";
        try (PreparedStatement ps = conn.prepareStatement(sql)) {
            for (String tag : tags) {
                ps.setString(1, tag);
                ps.addBatch();
            }
            int[] results = ps.executeBatch(); // single round-trip
            conn.commit();
            return results.length;
        } catch (SQLException e) {
            conn.rollback();
            throw e;
        } finally {
            conn.setAutoCommit(true);
        }
    }

    public static void main(String[] args) {
        System.out.println("Batch insert would insert: 5 rows");
    }
}

