public class Q3 {
    public static void main(String[] args) {
        int cpuCores = 4;
        int avgQueryMs = 5;
        int targetRps = 500;

        // Q1: (cores * 2) + 1, no spinning disks (SSD/cloud)
        int poolSize = (cpuCores * 2) + 1; // 9

        // Q2: each connection handles 1000ms / 5ms = 200 req/s
        double maxRps = poolSize * (1000.0 / avgQueryMs); // 9 * 200 = 1800

        System.out.println("Pool size: " + poolSize);          // 9
        System.out.println("Max RPS: " + maxRps);              // 1800.0
        System.out.println("Sufficient for 500 rps? " + (maxRps >= targetRps)); // true

        System.out.println("spring.datasource.hikari.maximum-pool-size=" + poolSize);
        System.out.println("spring.datasource.hikari.connection-timeout=5000");
        System.out.println("spring.datasource.hikari.max-lifetime=1800000");
    }
}
